//! JS-callable Pneuma TTS pipeline.
//!
//! Wraps the cross-target `TtsAcousticModel` + `HiFiGANVocoder` pair so
//! the Cloudflare-Worker `pneuma-station` can call
//! `synthesize_from_phonemes(ids: Vec<u32>) -> Vec<f32>` and ship the
//! resulting Float32 PCM back to the consciousness loop without ever
//! materialising text on the wire (the client phonemizes locally and
//! ships a `@a0n/bitwise` codec packet).
//!
//! Architectural mirror of `wasm_bindings::WasmLlamaPipeline` — same
//! "newtype around a Rust struct" shape, same Arc-borrow lifetime
//! discipline (the JS handle stays alive across `set_tensor` calls so
//! the host shim can stream tensor bytes after pipeline construction).
//!
//! Two backends, not one: the acoustic model and the HiFi-GAN vocoder
//! ship as separate `.knot` files (different tensor namespaces, different
//! quantizations, different layer counts). The host populates each
//! backend independently and hands both to `from_backends`. The pipeline
//! holds them as upcast `Arc<dyn WeightBackend>` references so subsequent
//! eviction calls on either JS handle continue to work.
//!
//! Lifetime / lifecycle notes:
//!  - JS host owns both `WasmHostBackend` instances. Pipeline borrows
//!    each (`&WasmHostBackend`) so `__wbg_ptr` doesn't get zeroed by
//!    wasm-bindgen's `_assertClass + __destroy_into_raw` chain.
//!  - `synthesize_from_phonemes` is `&mut self` (the acoustic model
//!    mutates an internal scratch buffer per call); each station serves
//!    requests serially inside its CF Worker isolate, so this is fine.
//!  - Sample rate is derived from `vocoder.config().sample_rate`
//!    (typically 22050 for Piper, matching the existing `/tts` route's
//!    `X-Sample-Rate` header).
//!
//! @see open-source/bitwise/src/phoneme-codec.ts — the wire codec.
//! @see apps/pneuma-station/src/tts-phonemes-route.ts — the route this
//!      pipeline backs.

use std::sync::Arc;
use wasm_bindgen::prelude::*;

use crate::loader::{parse_knot_codec, WeightBackend};
use crate::model_pneuma_tts_acoustic::{parse_tts_config, TtsAcousticModel};
use crate::model_pneuma_tts_vocoder::{parse_vocoder_config, HiFiGANVocoder};
use crate::wasm_bindings::WasmHostBackend;

/// JS-facing Pneuma TTS pipeline. Holds an acoustic model + vocoder pair
/// resolved against two host-populated weight backends.
#[wasm_bindgen]
pub struct WasmPneumaTtsPipeline {
    acoustic: TtsAcousticModel,
    vocoder: HiFiGANVocoder,
}

#[wasm_bindgen]
impl WasmPneumaTtsPipeline {
    /// Construct from two backends + their metadata JSON blobs.
    ///
    /// `acoustic_metadata_json` and `vocoder_metadata_json` are the
    /// stringified `KNOT` metadata sections (the same JSON the JS host
    /// already parses from the knot header). The acoustic blob carries
    /// the `TtsConfig` schema and the per-knot codec marker; the vocoder
    /// blob carries `VocoderConfig`. Schemas live in
    /// `model_pneuma_tts_acoustic.rs` / `model_pneuma_tts_vocoder.rs`.
    #[wasm_bindgen]
    pub fn from_backends(
        acoustic_backend: &WasmHostBackend,
        vocoder_backend: &WasmHostBackend,
        acoustic_metadata_json: String,
        vocoder_metadata_json: String,
    ) -> Result<WasmPneumaTtsPipeline, JsError> {
        // Parse both metadata blobs first so a malformed input fails
        // before we touch any tensor cache.
        let acoustic_meta: serde_json::Value = serde_json::from_str(&acoustic_metadata_json)
            .map_err(|e| JsError::new(&format!("acoustic metadata parse: {}", e)))?;
        let vocoder_meta: serde_json::Value = serde_json::from_str(&vocoder_metadata_json)
            .map_err(|e| JsError::new(&format!("vocoder metadata parse: {}", e)))?;

        let tts_config = parse_tts_config(&acoustic_meta)
            .map_err(|e| JsError::new(&format!("tts config: {}", e)))?;
        let codec = parse_knot_codec(&acoustic_meta);
        let voc_config = parse_vocoder_config(&vocoder_meta)
            .map_err(|e| JsError::new(&format!("vocoder config: {}", e)))?;

        // Upcast each backend to `Arc<dyn WeightBackend>`. We don't
        // consume the JS handles; subsequent `set_tensor` / `evict` calls
        // on the JS side continue to work.
        let acoustic_dyn: Arc<dyn WeightBackend> = acoustic_backend.as_weight_backend();
        let vocoder_dyn: Arc<dyn WeightBackend> = vocoder_backend.as_weight_backend();

        let acoustic = TtsAcousticModel::with_codec(tts_config, acoustic_dyn, codec);
        let vocoder = HiFiGANVocoder::new(voc_config, vocoder_dyn);

        Ok(Self { acoustic, vocoder })
    }

    /// Synthesize PCM from a phoneme-id stream.
    ///
    /// Same end-to-end shape as the smoke binary
    /// (`pneuma-tts-smoke.rs`):
    ///
    ///   acoustic.forward(phonemes) -> mel
    ///   vocoder.forward(mel)       -> pcm
    ///
    /// Returns the f32 mono PCM samples; sample rate is reported via
    /// `sample_rate()`. Errors on empty input / empty mel / empty pcm
    /// so the route handler can surface a 4xx/5xx with provenance
    /// instead of shipping silence.
    #[wasm_bindgen]
    pub fn synthesize_from_phonemes(&mut self, phoneme_ids: Vec<u32>) -> Result<Vec<f32>, JsError> {
        if phoneme_ids.is_empty() {
            return Err(JsError::new(
                "synthesize_from_phonemes: empty phoneme stream",
            ));
        }
        let mel = self.acoustic.forward(&phoneme_ids);
        if mel.is_empty() {
            return Err(JsError::new(
                "synthesize_from_phonemes: acoustic emitted empty mel",
            ));
        }
        let pcm = self.vocoder.forward(&mel);
        if pcm.is_empty() {
            return Err(JsError::new(
                "synthesize_from_phonemes: vocoder emitted empty pcm",
            ));
        }
        Ok(pcm)
    }

    /// Sample rate the vocoder will emit. Matches what the route handler
    /// puts in the `X-Sample-Rate` response header. Read once per
    /// session; doesn't change after construction.
    #[wasm_bindgen]
    pub fn sample_rate(&self) -> u32 {
        self.vocoder.config().sample_rate as u32
    }
}
